queries.sparql:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?script_supervisors a :Script_Supervisors .
    ?script_supervisors p:name ?name .
    ?script_supervisors p:Age ?age_f .
    FILTER((STR(?age_f) = "45" || STR(?age_f) = "45.0"))
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?costume_designers a :Costume_Designers .
    ?costume_designers p:name ?name .
    ?costume_designers p:Age ?age_f .
    FILTER((STR(?age_f) = "45" || STR(?age_f) = "45.0"))
    BIND(?name AS ?o0)
  }
}

